import{_ as t,o as e,c as o,a2 as d}from"./chunks/framework.gSjTt1Hm.js";const u=JSON.parse('{"title":"模型映射","description":"","frontmatter":{},"headers":[],"relativePath":"guide/model-map.md","filePath":"guide/model-map.md","lastUpdated":1783864095000}'),r={name:"guide/model-map.md"};function l(i,a,n,h,s,c){return e(),o("div",null,[...a[0]||(a[0]=[d('<h1 id="模型映射" tabindex="-1">模型映射 <a class="header-anchor" href="#模型映射" aria-label="Permalink to &quot;模型映射&quot;">​</a></h1><h2 id="什么是模型映射" tabindex="-1">什么是模型映射 <a class="header-anchor" href="#什么是模型映射" aria-label="Permalink to &quot;什么是模型映射&quot;">​</a></h2><p>模型映射允许你将一个模型名映射到另一个模型名。例如：</p><ul><li>客户端请求 <code>gpt-4</code> → 实际调用 <code>gpt-4o</code></li><li>客户端请求 <code>claude-3</code> → 实际调用 <code>claude-3-5-sonnet</code></li></ul><h2 id="配置模型映射" tabindex="-1">配置模型映射 <a class="header-anchor" href="#配置模型映射" aria-label="Permalink to &quot;配置模型映射&quot;">​</a></h2><p>在管理后台的「模型映射」页面配置：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>别名 (Alias)</td><td>客户端请求的模型名</td></tr><tr><td>目标模型 (Target)</td><td>实际调用的模型名</td></tr><tr><td>平台</td><td>限定在特定平台生效（可选）</td></tr></tbody></table><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h2><ol><li><strong>模型升级</strong>：旧模型名映射到新模型</li><li><strong>成本优化</strong>：将昂贵模型映射到性价比更高的模型</li><li><strong>多平台适配</strong>：同一别名在不同平台映射到不同目标</li></ol><h2 id="平台级模型发现" tabindex="-1">平台级模型发现 <a class="header-anchor" href="#平台级模型发现" aria-label="Permalink to &quot;平台级模型发现&quot;">​</a></h2><p>FWP 支持自动发现平台支持的模型列表，方便配置映射。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2>',12)])])}const m=t(r,[["render",l]]);export{u as __pageData,m as default};
